586: // digestConfigObjects is given all the API objects that configure
587: // cfgCtlr and writes its consequent new configState.
588: // Only invoke this in the one and only worker goroutine
589: func (cfgCtlr *configController) digestConfigObjects(newPLs []*flowcontrol.PriorityLevelConfiguration, newFSs []*flowcontrol.FlowSchema) (time.Duration, error) {
590: 	fsStatusUpdates := cfgCtlr.lockAndDigestConfigObjects(newPLs, newFSs)
591: 	var errs []error
592: 	currResult := updateAttempt{
593: 		timeUpdated:  cfgCtlr.clock.Now(),
594: 		updatedItems: sets.String{},
595: 	}
596: 	var suggestedDelay time.Duration
597: 	for _, fsu := range fsStatusUpdates {
598: 		// if we should skip this name, indicate we will need a delay, but continue with other entries
599: 		if cfgCtlr.shouldDelayUpdate(fsu.flowSchema.Name) {
600: 			if suggestedDelay == 0 {
601: 				suggestedDelay = time.Duration(30+rand.Intn(45)) * time.Second
602: 			}
603: 			continue
604: 		}
605: 
606: 		// if we are going to issue an update, be sure we track every name we update so we know if we update it too often.
607: 		currResult.updatedItems.Insert(fsu.flowSchema.Name)
608: 		if klogV := klog.V(4); klogV.Enabled() {
609: 			klogV.Infof("%s writing Condition %s to FlowSchema %s, which had ResourceVersion=%s, because its previous value was %s, diff: %s",
610: 				cfgCtlr.name, fsu.condition, fsu.flowSchema.Name, fsu.flowSchema.ResourceVersion, fcfmt.Fmt(fsu.oldValue), diff.Diff(fsu.oldValue, fsu.condition))
611: 		}
612: 
613: 		if err := apply(cfgCtlr.flowcontrolClient.FlowSchemas(), fsu, cfgCtlr.asFieldManager); err != nil {
614: 			if apierrors.IsNotFound(err) {
615: 				// This object has been deleted.  A notification is coming
616: 				// and nothing more needs to be done here.
617: 				klog.V(5).Infof("%s at %s: attempted update of concurrently deleted FlowSchema %s; nothing more needs to be done", cfgCtlr.name, cfgCtlr.clock.Now().Format(timeFmt), fsu.flowSchema.Name)
618: 			} else {
619: 				errs = append(errs, fmt.Errorf("failed to set a status.condition for FlowSchema %s: %w", fsu.flowSchema.Name, err))
620: 			}
621: 		}
622: 	}
623: 	cfgCtlr.addUpdateResult(currResult)
624: 
625: 	return suggestedDelay, utilerrors.NewAggregate(errs)
626: }
